from abc import ABC, abstractmethodclass ICoveragePyEbyeAggregator(ABC):	"""		This is an aggregator for statement coverage data generated by coverage.py,        which corresponds to the entity-level statement coverage metric.                A JSON file is generated, and the aggregated data is returned in the following format:                        - A list of JSON dictionaries, each containing:							* "module" (str): The name of the module, specified as a "dotted path" starting from the Focal Project Root Path, to which the standalone entity whose coverage percentage is being evaluated belongs.                * "class" (str): The name of the class, if any, to which the standalone entity belongs. If the entity is a function, this field is an empty string                * "entity" (str): The name of the standalone code entity for which the coverage percentage is evaluated                * "coverage" (float): The measured coverage percentage, as a `float` between 0 and 1 inclusive, for the specified standalone entity						The format of the "coverage.py" report being processed is specified by the descendants of this interface	"""			@abstractmethod	def add_exclusion(self, excl_entity: str, pass_onerror: bool=False):		"""			Adds the specified autonomous entity to the list of excluded entities            for subsequent data aggregations                        Parameters            ----------				excl_entity: str					A string containing the fully-qualified name of the standalone entity                    to be excluded in this aggregator.                    The name is formatted as follows:                        `<dotted_module_path>.[<dollarsep_class_path>$]<entity_name>`                    where:                    						- [...] represents an optional element;                        - `<dollarsep_class_path>` is the class path (if any) containing the entity `<entity_name>`;                        - `<entity_name>` is the name of the standalone entity										pass_onerror: bool                    Optional. Default = `False`. A boolean indicating whether to ignore                    any error related to the exclusion already performed on the standalone entity                    provided                                Raises            ------				ValueError                    Occurs if:                                            - The `excl_entity` parameter is `None` or an empty string                        - If `pass_onerror=False` and the `excl_entity` parameter represents an entity that has already been excluded in this aggregator		"""		pass			@abstractmethod	def rem_exclusion(self, excl_entity: str, pass_onerror: bool=False):		"""			Rimuove l' entità autonoma specificata di cui era stata richiesta			l' esclusione precedentemente						Parameters			----------				excl_entity: str					Una stringa contenente il nome fully-qualified dell' entità autonoma precedentemente					esclusa da questo aggregatore.					Il nome è formattato come segue:						`<dotted_module_path>.[<dollarsep_class_path>$]<entity_name>`					in cui:						- [...] rappresenta qualcosa di opzionale						- `<dollarsep_class_path>` è l' eventuale percorso di classi che contiene l' entità `<entity_name>`						- `<entity_name>` è il nome dell' entità autonoma										pass_onerror: bool					Opzionale. Default = `False`. Un booleano che indica se bisogna ignorare					un eventuale errore legato all' esclusione mai effettuata dell' entità autonoma					fornita						Raises			------				ValueError					Si verifica se:											- Il parametro `excl_entity` ha valore `None` o è una stringa vuota						- Se il parametro `pass_onerror=False` e il parametro `excl_entity` rappresenta un entità che non è mai stata esclusa in questo aggregatore		"""		pass			@abstractmethod	def aggregate(			self,	        report_path: str,			focal_root: str,			aggr_path: str,	):		"""			Aggregates the statement coverage data stored in the report at the data path,            converting it into entity-level statement coverage data based on the standalone code entities (functions or methods) defined in the module files within the provided Focal Project Root Path.			Any standalone entities selected for exclusion prior to calling this operation are omitted.			Upon completion of the aggregation, the data is written, in the format described in the interface contract, to the file at the path `aggr_path`						Parameters            ----------                report_path: str                    A string representing the path containing the coverage.py report to be used.                                    focal_root: str					A string representing the Focal Project Root Path associated with the report                    provided, where the functions used to aggregate the data are located                                    aggr_path: str                    A string representing the path that will contain the aggregated data in the format                    described in the interface contract			Raises            ------                ValueError                    Occurs if:                        - The `report_path` parameter is `None` or an empty string                        - The `focal_root` parameter is `None` or an empty string						- The `aggr_path` parameter is `None` or an empty string                        - The `focal_root` parameter represents a non-existent or inaccessible path                        - The `aggr_path` parameter represents a non-existent or inaccessible path										WrongReportTypeError                    Occurs if `report_path` represents a report of a type                    not handled by the descendants of this interface		"""		pass